sp_widget.css:
.detech-flex-shadow-25 {
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
} 

.component-selector {
  background: #F5F7F9;
}

/* mmcc 14-Nov-2022 seems not used; leaving in if needed in the future
.component-selector-divider {
  width: 100%;
  height: 2px;
  background-color: rgba(221, 221, 221, 1);
}
*/

.component-selector-header{
  color: rgba(117, 117, 117, 1); /*508 AA*/
  width: 100%;
  padding: 14px 20px 14px 20px;
  font-size: 14px;
  font-weight: 400;
  text-transform: uppercase;
}


.ul-selector {
  margin: 0px;
  padding: 0px;
  list-style-type: none;
  color:#757575;
}

.li-flex-row {
  display: flex;
  flex-grow:0;
  width:100%;
  flex-direction:row;
}

.flex-text {
  flex-grow:1;
}

/* mmcc 14-Nov-2022 seems not used
.li-flex-row-child:first-child {
  flex-grow:1;
}
*/

.li-flex-row-left-pointer {
  width: 0px;
  height: 0px;
  border-left: 10px solid transparent;
  border-right: 10px solid  white;
  border-top: 10px solid  transparent;
  border-bottom: 10px solid  transparent;
  margin: 0px auto;
  z-index: 1000;
}

.li-selector {
  padding: 14px 0px 14px 40px;
  width: 100%;
  color: rgba(0, 0, 0, 1);
  font-size: 14px;
  font-weight: 400;
  cursor:pointer;
}

.li-selector:hover{
  background-color: rgba(217, 237, 247, 1);
}

.li-selected{
  background-color: rgba(231, 244, 253, 1);
}

